{"content": """"配置文件加载模块 - 支持 YAML 格式"""

from pathlib import Path

import yaml
from loguru import logger
from result import Result, Ok, Err

from constants import (
    LOG_MSG_CONFIG_LOADED,
    ERROR_MSG_CONFIG_NOT_FOUND,
    ERROR_MSG_CONFIG_INVALID_YAML,
    ERROR_MSG_CONFIG_MISSING_FIELD,
)
from models import EndpointConfig, HealthCheckConfig


def load_config(config_path: str | Path) -> Result[HealthCheckConfig, str]:
    """
    从 YAML 配置文件加载端点配置

    配置文件格式:
    ```yaml
    endpoints:
      - name: "API Server"
        url: "https://api.example.com/health"
        expected_status: 200
        timeout: 10.0
      - name: "Web Server"
        url: "https://www.example.com"
        expected_status: 200
        timeout: 5.0
    ```

    Returns:
        Ok(HealthCheckConfig) 或 Err(error_message)
    """
    config_path = Path(config_path)

    # 检查文件是否存在
    if not config_path.exists():
        error_msg = ERROR_MSG_CONFIG_NOT_FOUND.format(path=config_path)
        logger.error(error_msg)
        return Err(error_msg)

    try:
        # 读取并解析 YAML
        with open(config_path, 'r', encoding='utf-8') as f:
            config_data = yaml.safe_load(f)

        # 验证结构
        if not isinstance(config_data, dict):
            error_msg = ERROR_MSG_CONFIG_INVALID_YAML.format(
                error="Root element must be a dictionary"
            )
            return Err(error_msg)

        if 'endpoints' not in config_data:
            error_msg = ERROR_MSG_CONFIG_MISSING_FIELD.format(field='endpoints')
            return Err(error_msg)

        if not isinstance(config_data['endpoints'], list):
            error_msg = ERROR_MSG_CONFIG_INVALID_YAML.format(
                error="'endpoints' must be a list"
            )
            return Err(error_msg)

        # 解析端点配置
        endpoints = []
        for i, endpoint_data in enumerate(config_data['endpoints']):
            # 验证必需字段
            required_fields = ['name', 'url']
            for field in required_fields:
                if field not in endpoint_data:
                    error_msg = ERROR_MSG_CONFIG_MISSING_FIELD.format(
                        field=f"endpoints[{i}].{field}"
                    )
                    return Err(error_msg)

            try:
                endpoint = EndpointConfig(
                    name=endpoint_data['name'],
                    url=endpoint_data['url'],
                    expected_status=endpoint_data.get('expected_status', 200),
                    timeout=float(endpoint_data.get('timeout', 30.0)),
                )
                endpoints.append(endpoint)
            except (ValueError, TypeError) as e:
                error_msg = ERROR_MSG_CONFIG_INVALID_YAML.format(
                    error=f"Invalid endpoint configuration at index {i}: {str(e)}"
                )
                return Err(error_msg)

        # 创建配置对象
        try:
            config = HealthCheckConfig(endpoints=endpoints)
            logger.info(LOG_MSG_CONFIG_LOADED.format(
                path=config_path,
                count=len(endpoints),
            ))
            return Ok(config)
        except ValueError as e:
            error_msg = ERROR_MSG_CONFIG_INVALID_YAML.format(error=str(e))
            return Err(error_msg)

    except yaml.YAMLError as e:
        error_msg = ERROR_MSG_CONFIG_INVALID_YAML.format(error=str(e))
        logger.error(error_msg)
        return Err(error_msg)
    except Exception as e:
        error_msg = f"Unexpected error loading config: {type(e).__name__}: {str(e)}"
        logger.error(error_msg)
        return Err(error_msg)
